"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useToast } from "@/hooks/use-toast";
import Link from "next/link";
import { CalendarDays, Loader2 } from "lucide-react";

export default function SignupPage() {
  const [loading, setLoading] = useState(false);
  const router = useRouter();
  const { toast } = useToast();

  const [formData, setFormData] = useState({
    email: "",
    password: "",
    name: "",
    usn_emp: "",
    role: "student",
    program: "",
    year: "",
  });

  const handleSignup = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    // Mock Signup Logic using LocalStorage
    setTimeout(() => {
      try {
        const users = JSON.parse(localStorage.getItem('users') || '[]');
        
        if (users.find((u: any) => u.email === formData.email)) {
          toast({ variant: "destructive", title: "Error", description: "Email already exists." });
          setLoading(false);
          return;
        }

        const newUser = {
          ...formData,
          uid: formData.usn_emp, // USN or EMP is the ID
          // Default profile pic path logic (could be /public/profile/...)
          profilePic: `https://picsum.photos/seed/${formData.usn_emp}/400/200`,
        };

        users.push(newUser);
        localStorage.setItem('users', JSON.stringify(users));
        localStorage.setItem('currentUser', JSON.stringify(newUser));

        toast({ title: "Account created", description: "Welcome to AttendanceWise!" });
        router.push("/dashboard");
        window.dispatchEvent(new Event('storage'));
      } catch (err) {
        toast({ variant: "destructive", title: "Error", description: "Failed to save account." });
      } finally {
        setLoading(false);
      }
    }, 800);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-accent/30 p-4">
      <Card className="w-full max-w-md shadow-xl border-primary/10">
        <CardHeader className="space-y-1 text-center">
          <div className="flex justify-center mb-4">
            <div className="bg-primary p-2 rounded-xl">
              <CalendarDays className="h-8 w-8 text-white" />
            </div>
          </div>
          <CardTitle className="text-2xl font-bold text-primary">Create Account</CardTitle>
          <CardDescription>Enter your details to register as a student or teacher</CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSignup} className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Full Name</Label>
                <Input placeholder="John Doe" required value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
              </div>
              <div className="space-y-2">
                <Label>ID Number (USN/EMP)</Label>
                <Input placeholder="250011..." required value={formData.usn_emp} onChange={e => setFormData({...formData, usn_emp: e.target.value})} />
              </div>
            </div>
            <div className="space-y-2">
              <Label>Email</Label>
              <Input type="email" placeholder="email@school.edu" required value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} />
            </div>
            <div className="space-y-2">
              <Label>Password</Label>
              <Input type="password" required value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} />
            </div>
            <div className="space-y-2">
              <Label>Role</Label>
              <Select defaultValue="student" onValueChange={v => setFormData({...formData, role: v})}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="student">Student</SelectItem>
                  <SelectItem value="teacher">Teacher</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="grid grid-cols-2 gap-4 animate-in fade-in slide-in-from-top-2 duration-300">
              <div className="space-y-2">
                <Label>Program</Label>
                <Input placeholder="BSCpE" value={formData.program} onChange={e => setFormData({...formData, program: e.target.value})} />
              </div>
              <div className="space-y-2">
                <Label>Year Level</Label>
                <Input placeholder="1st Year" value={formData.year} onChange={e => setFormData({...formData, year: e.target.value})} />
              </div>
            </div>
            <Button type="submit" className="w-full bg-primary hover:bg-primary/90 mt-4 text-white font-bold" disabled={loading}>
              {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : "Sign Up"}
            </Button>
            <p className="text-center text-sm text-muted-foreground mt-4">
              Already have an account? <Link href="/login" className="text-primary font-semibold hover:underline">Login</Link>
            </p>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}